import base64
from xml.dom.minidom import Document

def build_saml_request(destination, user_info):
    # Create a new XML document
    doc = Document()
    
    # Create the SAML request element
    saml_request = doc.createElement('samlp:AuthnRequest')
    saml_request.setAttribute('xmlns:samlp', 'urn:oasis:names:tc:SAML:2.0:protocol')
    saml_request.setAttribute('ID', '_1')
    saml_request.setAttribute('Version', '2.0')
    saml_request.setAttribute('IssueInstant', '2023-04-01T00:00:00Z')
    saml_request.setAttribute('Destination', destination)
    
    # Create the Issuer element
    issuer = doc.createElement('saml:Issuer')
    issuer.setAttribute('xmlns:saml', 'urn:oasis:names:tc:SAML:2.0:assertion')
    issuer.appendChild(doc.createTextNode(user_info['issuer']))
    saml_request.appendChild(issuer)
    
    # Create the NameIDPolicy element
    name_id_policy = doc.createElement('samlp:NameIDPolicy')
    name_id_policy.setAttribute('Format', 'urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified')
    name_id_policy.setAttribute('AllowCreate', 'true')
    saml_request.appendChild(name_id_policy)
    
    # Append the SAML request element to the document
    doc.appendChild(saml_request)
    
    # Serialize the XML document to a string
    saml_xml = doc.toprettyxml()
    
    # Encode the SAML request in base64
    encoded_saml_request = base64.b64encode(saml_xml.encode()).decode('utf-8')
    
    return encoded_saml_request

def post_saml_request(encoded_saml_request, idp_url):
    import requests
    
    # Prepare the data to be posted
    payload = {
        'SAMLRequest': encoded_saml_request,
        # Add other necessary fields if required by your IdP
    }
    
    # Send the POST request
    response = requests.post(idp_url, data=payload)
    
    return response

